using Microsoft.AspNetCore.Mvc;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

namespace YourNamespace.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class SchedulerController : ControllerBase
    {
        private readonly ISchedulerService _schedulerService;

        public SchedulerController(ISchedulerService schedulerService)
        {
            _schedulerService = schedulerService;
        }

        [HttpGet]
        public async Task<ActionResult<IEnumerable<Scheduler>>> GetSchedulers()
        {
            var schedulers = await _schedulerService.GetSchedulersAsync();
            return Ok(schedulers);
        }

        [HttpPost]
        public async Task<ActionResult<Scheduler>> CreateScheduler(Scheduler scheduler)
        {
            if (!ModelState.IsValid)
            {
                return BadRequest(ModelState);
            }

            var createdScheduler = await _schedulerService.CreateSchedulerAsync(scheduler);
            return CreatedAtAction(nameof(GetSchedulers), new { id = createdScheduler.Id }, createdScheduler);
        }

        [HttpPut("{id}")]
        public async Task<ActionResult> UpdateScheduler(int id, Scheduler scheduler)
        {
            if (id != scheduler.Id || !ModelState.IsValid)
            {
                return BadRequest();
            }

            await _schedulerService.UpdateSchedulerAsync(scheduler);
            return NoContent();
        }

        [HttpDelete("{id}")]
        public async Task<ActionResult> DeleteScheduler(int id)
        {
            await _schedulerService.DeleteSchedulerAsync(id);
            return NoContent();
        }
    }

    public interface ISchedulerService
    {
        Task<IEnumerable<Scheduler>> GetSchedulersAsync();
        Task<Scheduler> CreateSchedulerAsync(Scheduler scheduler);
        Task UpdateSchedulerAsync(Scheduler scheduler);
        Task DeleteSchedulerAsync(int id);
    }

    public class Scheduler
    {
        public int Id { get; set; }
        public string Name { get; set; }
        public string Description { get; set; }
        // Add other properties as needed
    }
}
